class Solution {
public:
    bool canConstruct(string s, int k) {
        int charCount[26] = {0};
        for (char c : s) {
            charCount[c - 'a']++;
        }
        int oddCount = 0;
        for (int count : charCount) {
            if (count % 2 == 1) {
                oddCount++;
            }
        }
        return k <= s.size() && (k % 2 == 0 || oddCount <= k);
    }
};
```

